  ('dietitian-moex-07144', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '某生以「標準平板計數法」測貢丸之生菌數，在 100 稀釋倍數所得菌落數為：235、168（二重複），則 此樣品的生菌數，應表示為： 202 × 102 CFU/mL  202 × 102 CFU/g  2.0 × 104 CFU/g  2.0 × 104 CFU/mL', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
