  ('dietitian-moex-07148', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '以實驗動物進行致畸胎性實驗所獲得的評估結果，對人類健康具有下列何種意義？ 可做進一步實驗或評估的重要參考依據  可以直接判定對人類也有完全相同的情形 可據以推算人類之每日最高攝入量（ADI）  所獲得之結果即為半數致死劑量', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
